import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import styles from './CollectionPage.module.css';
import Header from '../components/Header';
import {
  banners,
  womenProducts,
  menProducts,
  eyewearProducts,
} from '../data/mockData';

const collectionMap = {
  women: {
    banner: banners[0],
    products: womenProducts,
    label: 'Womenswear',
  },
  men: {
    banner: banners[1],
    products: menProducts,
    label: 'Menswear',
  },
  collab: {
    banner: banners[2],
    products: eyewearProducts,
    label: 'EFFECTOR × RECTO',
  },
};

function ProductCard({ product }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className={styles.card}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div className={styles.imageWrap} style={{ background: product.bg }}>
        <img
          src={product.imageUrl}
          alt={product.name}
          className={styles.productImage}
        />
        <div className={`${styles.overlay} ${hovered ? styles.overlayVisible : ''}`}>
          <p className={styles.overlayName}>{product.name}</p>
          <p className={styles.overlayColor}>{product.color}</p>
          <p className={styles.overlayPrice}>
            {product.price.toLocaleString()} {product.currency}
          </p>
        </div>
      </div>
    </div>
  );
}

function CollectionPage() {
  const { id } = useParams();
  const collection = collectionMap[id];

  if (!collection) {
    return (
      <div className={styles.notFound}>
        <Header />
        <div className={styles.notFoundBody}>
          <p>Collection not found.</p>
          <Link to="/" className={styles.backLink}>Back to Home</Link>
        </div>
      </div>
    );
  }

  const { banner, products, label } = collection;

  return (
    <div className={styles.page}>
      <Header />

      {/* Hero */}
      <section className={styles.hero} style={{ background: banner.bg }}>
        {banner.img && (
          <img src={banner.img} alt="" className={styles.heroBg} />
        )}
        <div className={styles.heroOverlay}>
          <p className={styles.heroYear}>2026</p>
          <h1 className={styles.heroTitle}>{banner.title}</h1>
        </div>
      </section>

      {/* Collection header */}
      <div className={styles.collectionHeader}>
        <h2 className={styles.collectionTitle}>{label}</h2>
        <p className={styles.collectionCount}>{products.length} Products</p>
      </div>

      {/* Product grid */}
      <div className={styles.grid}>
        {products.map((product) => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>

      {/* Back link */}
      <div className={styles.backWrap}>
        <Link to="/" className={styles.backLink}>← Back to Home</Link>
      </div>
    </div>
  );
}

export default CollectionPage;
